### Tool Class — `ApiTools.cs`

```csharp
using ModelContextProtocol.Server;
using System.ComponentModel;
using System.Text.Json;

[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    [McpServerTool, Description("Fetch a resource by its unique identifier.")]
    public async Task<string> GetResource(
        [Description("The unique resource ID (e.g. '42')")] string id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching resource {Id}", id);
        var response = await httpClient.GetAsync($"/api/resources/{id}", cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool, Description("Search resources by keyword.")]
    public async Task<string> SearchResources(
        [Description("Search query keyword")] string query,
        [Description("Max results to return (1-50)")] int limit = 10,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Searching for {Query}, limit {Limit}", query, limit);
        var response = await httpClient.GetAsync(
            $"/api/resources?q={Uri.EscapeDataString(query)}&limit={limit}",
            cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool(Destructive = true), Description("Create a new resource.")]
    public async Task<string> CreateResource(
        [Description("Display name for the resource")] string name,
        [Description("Resource content body")] string content,
        CancellationToken cancellationToken = default)
    {
        var payload = JsonSerializer.Serialize(new { name, content });
        var httpContent = new StringContent(payload, System.Text.Encoding.UTF8, "application/json");
        var response = await httpClient.PostAsync("/api/resources", httpContent, cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }
}
```

### `Program.cs` — stdio transport

```csharp
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;

var builder = Host.CreateApplicationBuilder(args);

// CRITICAL: route all logging to stderr so stdout stays clean for JSON-RPC
builder.Logging.AddConsole(options =>
    options.LogToStandardErrorThreshold = LogLevel.Trace);

builder.Services.AddHttpClient<ApiTools>(client =>
{
    client.BaseAddress = new Uri("https://api.example.com");
    client.DefaultRequestHeaders.Add("Accept", "application/json");
});

builder.Services.AddMcpServer(options =>
{
    options.ServerInfo = new() { Name = "ApiMcpServer", Version = "1.0.0" };
})
.WithStdioServerTransport()
.WithToolsFromAssembly();

await builder.Build().RunAsync();
```

